head.script:
scwin.onpageload = function () {

    scwin.f_SetDataHeader();
    scwin.f_SetDefaultData();
};

/**
 * 조회용 dlt setting
 */
scwin.f_SetDataHeader = function () {
    ds_condition.insertRow();
};

/**
 * 조회용 dlt data setting
 */
scwin.f_SetDefaultData = async function () {
    // 작업일자
    const today = $c.date.getServerDateTime().slice(0,6);
    ica_wrkDt.setValue(`${today}01`);

    // 점소 바인딩
    await $c.sbm.execute(sbm_lobranCd);
    // 점소 sort
    co_ds_combo1.sort("code", 0);
    lc_lobranCd.setValue($c.data.getMemInfo("lobranCd"));

    // focus
    lc_lobranCd.focus();
};

/**
 * 조회
 */
scwin.f_Retrieve = function () {

    // if (!$c.gus.cfValidate([lc_lobranCd, ica_wrkDt])) {
    //     return;
    // }

    if ($c.gus.cfIsNull(ica_wrkDt.getValue())) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_002, new Array("작업일자")).then(() => {
            ica_wrkDt.focus();
        });
        return false;
    }

    ds_condition.setCellData(0, "lobranCd", lc_lobranCd.getValue());
    ds_condition.setCellData(0, "wrkDt", ica_wrkDt.getValue());

    $c.sbm.execute(sbm_retrieve);
};

/**
 * 조회조건 초기화
 */
scwin.f_InitObjects = function () {
    $c.gus.cfInitObjects(tb_mainData);
    scwin.f_SetDefaultData();
};

/**
 * excel download
 */
scwin.gridToExcel = function() {

    const grdId = this.opts.gridID;
    const grdObj = $c.util.getComponent(grdId);
    const excelTitle = $c.util.getComponent(this.opts.grp).getUserData("userData1");
    const excelSubtitle = `점소 | ${lc_lobranCd.getText(true)} | 작업일자 | ${ica_wrkDt.getValue()}`;
    const excelMurgeCnt = grdObj.hiddenList.filter(val => val === false).length;

    const options = {
        fileName : `${excelTitle}.xlsx`,
        sheetName : excelTitle,
        startRowIndex : 3,
        bodyWordwrap : true,
        evenRowBackgroundColor : "#f5fff5"
    };

    const infoArr = [
        {rowIndex : 0, colIndex : 0, rowSpan : 1, colSpan : excelMurgeCnt, text : excelTitle, textAlign : "center", drawBorder : false, fontSize : "16px"},
        {rowIndex : 2, colIndex : 0, rowSpan : 1, colSpan : 1, text : excelSubtitle, textAlign : "left", drawBorder : false, fontSize : "10px"}
    ];

    $c.data.downloadGridViewExcel(grdObj, options, infoArr);

};

scwin.ds_eqDay_OnLoadCompleted = function () {
    totalRows.setValue(ds_eqDay.getRowCount());
};

scwin.ds_eqNight_OnLoadCompleted = function () {
    totalRows2.setValue(ds_eqNight.getRowCount());
};

scwin.ds_stvDay_OnLoadCompleted = function () {
    totalRows3.setValue(ds_stvDay.getRowCount());
};

scwin.ds_stvNight_OnLoadCompleted = function () {
    totalRows4.setValue(ds_stvNight.getRowCount());
};
